1	import { type RepoSnapshot, RepoSnapshotSchema } from "./schemas";
2	
3	const USER_AGENT = "content-factory-agent";
4	const README_MAX = 12_000;
5	
6	export type ParsedRepo = { owner: string; name: string };
7	
8	export function parseRepoUrl(input: string): ParsedRepo {
9		const trimmed = input.trim();
10		if (trimmed.length === 0) {
11			throw new Error("repo input is empty");
12		}
13	
14		const ghShort = trimmed.match(/^gh:([^/\s]+)\/([^/\s]+?)\/?$/i);
15		if (ghShort?.[1] && ghShort[2]) {
16			return { owner: ghShort[1], name: stripGitSuffix(ghShort[2]) };
17		}
18	
19		const httpUrl = trimmed.match(
20			/^https?:\/\/github\.com\/([^/\s]+)\/([^/\s?#]+?)\/?(?:[?#].*)?$/i,
21		);
22		if (httpUrl?.[1] && httpUrl[2]) {
23			return { owner: httpUrl[1], name: stripGitSuffix(httpUrl[2]) };
24		}
25	
26		throw new Error(`unsupported repo input: ${input}`);
27	}
28	
29	function stripGitSuffix(name: string): string {
30		return name.endsWith(".git") ? name.slice(0, -4) : name;
31	}
32	
33	async function ghFetch(path: string): Promise<unknown> {
34		const res = await fetch(`https://api.github.com${path}`, {
35			headers: {
36				"User-Agent": USER_AGENT,
37				Accept: "application/vnd.github+json",
38			},
39		});
40		if (!res.ok) {
41			throw new Error(`github ${path} responded ${res.status}`);
42		}
43		return res.json();
44	}
45	
46	type GhRepo = {
47		description: string | null;
48		language: string | null;
49		topics?: string[];
50		stargazers_count: number;
51	};
52	
53	type GhReadme = { content: string; encoding: string };
54	type GhCommit = { commit: { message: string; author: { date: string } } };
55	
56	export async function fetchRepoSnapshot(input: string): Promise<RepoSnapshot> {
57		const { owner, name } = parseRepoUrl(input);
58	
59		const [repoRaw, readmeRaw, commitsRaw] = await Promise.all([
60			ghFetch(`/repos/${owner}/${name}`),
61			ghFetch(`/repos/${owner}/${name}/readme`).catch(() => null),
62			ghFetch(`/repos/${owner}/${name}/commits?per_page=20`).catch(() => []),
63		]);
64	
65		const repo = repoRaw as GhRepo;
66		const readme = decodeReadme(readmeRaw as GhReadme | null);
67		const recentCommits = (commitsRaw as GhCommit[]).map((c) => ({
68			message: c.commit.message.split("\n", 1)[0] ?? "",
69			date: c.commit.author?.date ?? "",
70		}));
71	
72		return RepoSnapshotSchema.parse({
73			owner,
74			name,
75			description: repo.description ?? null,
76			primaryLanguage: repo.language ?? null,
77			topics: repo.topics ?? [],
78			stars: repo.stargazers_count ?? 0,
79			readme,
80			recentCommits,
81		});
82	}
83	
84	function decodeReadme(raw: GhReadme | null): string {
85		if (!raw) return "";
86		if (raw.encoding !== "base64") return raw.content.slice(0, README_MAX);
87		const decoded = Buffer.from(raw.content, "base64").toString("utf8");
88		return decoded.slice(0, README_MAX);
89	}
