1	import { type RepoSnapshot, RepoSnapshotSchema } from "./schemas";
2	
3	const USER_AGENT = "content-factory-agent";
4	const README_MAX = 12_000;
5	
6	export type ParsedRepo = { owner: string; name: string };
7	
8	// GitHub-permitted segment chars: alphanumerics, dot, dash, underscore.
9	const SEGMENT = /^[A-Za-z0-9._-]+$/;
10	
11	export function parseRepoUrl(input: string): ParsedRepo {
12		const trimmed = input.trim();
13		if (trimmed.length === 0) {
14			throw new Error("repo input is empty");
15		}
16	
17		const httpUrl = trimmed.match(
18			/^https?:\/\/(?:www\.)?github\.com\/([^/\s?#]+)\/([^/\s?#]+?)\/?(?:[?#].*)?$/i,
19		);
20		if (httpUrl?.[1] && httpUrl[2]) {
21			const owner = httpUrl[1];
22			const name = stripGitSuffix(httpUrl[2]);
23			if (!SEGMENT.test(owner) || !SEGMENT.test(name)) {
24				throw new Error(`unsupported repo input: ${input}`);
25			}
26			return { owner, name };
27		}
28	
29		throw new Error(`unsupported repo input: ${input}`);
30	}
31	
32	function stripGitSuffix(name: string): string {
33		return name.endsWith(".git") ? name.slice(0, -4) : name;
34	}
35	
36	async function ghFetch(path: string): Promise<unknown> {
37		const headers: Record<string, string> = {
38			"User-Agent": USER_AGENT,
39			Accept: "application/vnd.github+json",
40		};
41		const token = process.env.GITHUB_TOKEN;
42		if (token) headers.Authorization = `Bearer ${token}`;
43		const res = await fetch(`https://api.github.com${path}`, { headers });
44		if (!res.ok) {
45			throw new Error(`github ${path} responded ${res.status}`);
46		}
47		return res.json();
48	}
49	
50	type GhRepo = {
51		description: string | null;
52		language: string | null;
53		topics?: string[];
54		stargazers_count: number;
55	};
56	
57	type GhReadme = { content: string; encoding: string };
58	type GhCommit = { commit: { message: string; author: { date: string } } };
59	
60	export async function fetchRepoSnapshot(input: string): Promise<RepoSnapshot> {
61		const { owner, name } = parseRepoUrl(input);
62	
63		const ownerEnc = encodeURIComponent(owner);
64		const nameEnc = encodeURIComponent(name);
65		const [repoRaw, readmeRaw, commitsRaw] = await Promise.all([
66			ghFetch(`/repos/${ownerEnc}/${nameEnc}`),
67			ghFetch(`/repos/${ownerEnc}/${nameEnc}/readme`).catch(() => null),
68			ghFetch(`/repos/${ownerEnc}/${nameEnc}/commits?per_page=20`).catch(
69				() => [],
70			),
71		]);
72	
73		const repo = repoRaw as GhRepo;
74		const readme = decodeReadme(readmeRaw as GhReadme | null);
75		const recentCommits = (commitsRaw as GhCommit[]).map((c) => ({
76			message: c.commit.message.split("\n", 1)[0] ?? "",
77			date: c.commit.author?.date ?? "",
78		}));
79	
80		return RepoSnapshotSchema.parse({
81			owner,
82			name,
83			description: repo.description ?? null,
84			primaryLanguage: repo.language ?? null,
85			topics: repo.topics ?? [],
86			stars: repo.stargazers_count ?? 0,
87			readme,
88			recentCommits,
89		});
90	}
91	
92	function decodeReadme(raw: GhReadme | null): string {
93		if (!raw) return "";
94		if (raw.encoding !== "base64") return raw.content.slice(0, README_MAX);
95		const decoded = Buffer.from(raw.content, "base64").toString("utf8");
96		return decoded.slice(0, README_MAX);
97	}
